"use strict";(globalThis.webpackChunksite=globalThis.webpackChunksite||[]).push([[8156],{218(e,n,t){t.r(n),t.d(n,{assets:()=>d,contentTitle:()=>o,default:()=>u,frontMatter:()=>s,metadata:()=>r,toc:()=>c});const r=JSON.parse('{"id":"uganda-regulatory-architecture/tiered-lending-framework","title":"10.2 The Tiered Lending Framework","description":"Uganda\'s lending sector is structured in four tiers under the Financial Institutions Act (as amended) and the Tier 4 Microfinance Institutions and Money Lenders Act 2016. The LendingVault operates as an interface layer between licensed MFI lenders (Tier III or Tier IV) and cooperative borrowers. The key regulatory question is whether the LendingVault itself constitutes a lending business requiring UMRA licensing, or whether it functions as a technology platform through which licensed lenders deploy capital.","source":"@site/docs/10-uganda-regulatory-architecture/10-2-tiered-lending-framework.md","sourceDirName":"10-uganda-regulatory-architecture","slug":"/uganda-regulatory-architecture/tiered-lending-framework","permalink":"/docs/docs/uganda-regulatory-architecture/tiered-lending-framework","draft":false,"unlisted":false,"editUrl":"https://github.com/AsiliChain/docs/docs/10-uganda-regulatory-architecture/10-2-tiered-lending-framework.md","tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"id":"tiered-lending-framework","title":"10.2 The Tiered Lending Framework","sidebar_position":2},"sidebar":"tutorialSidebar","previous":{"title":"10.1 The Regulatory Landscape","permalink":"/docs/docs/uganda-regulatory-architecture/regulatory-landscape"},"next":{"title":"10.3 Mobile Money and KYC Requirements","permalink":"/docs/docs/uganda-regulatory-architecture/mobile-money-and-kyc"}}');var i=t(4848),a=t(8453);const s={id:"tiered-lending-framework",title:"10.2 The Tiered Lending Framework",sidebar_position:2},o=void 0,d={},c=[];function l(e){const n={p:"p",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.p,{children:"Uganda's lending sector is structured in four tiers under the Financial Institutions Act (as amended) and the Tier 4 Microfinance Institutions and Money Lenders Act 2016. The LendingVault operates as an interface layer between licensed MFI lenders (Tier III or Tier IV) and cooperative borrowers. The key regulatory question is whether the LendingVault itself constitutes a lending business requiring UMRA licensing, or whether it functions as a technology platform through which licensed lenders deploy capital."}),"\n",(0,i.jsx)(n.p,{children:"The recommended structure, based on legal counsel familiar with UMRA's digital lending guidelines, is for AsiliChain Ltd (Uganda) to register as a technology service provider to licensed lenders, not as a lender itself. The licensed MFI partners - UGAFODE, ENCOT, Pride Microfinance - deploy capital into the LendingVault under their existing licences and bear the regulatory lending relationship with the cooperative. AsiliChain provides the collateral valuation infrastructure, the credit scoring data, and the auto-repayment mechanism. This structure mirrors how fintech-as-infrastructure operates in Kenya and Rwanda and is consistent with UMRA's 2024 Digital Lending Guidelines framing of technology providers versus lenders."})]})}function u(e={}){const{wrapper:n}={...(0,a.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(l,{...e})}):l(e)}},8453(e,n,t){t.d(n,{R:()=>s,x:()=>o});var r=t(6540);const i={},a=r.createContext(i);function s(e){const n=r.useContext(a);return r.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function o(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),r.createElement(a.Provider,{value:n},e.children)}}}]);